	private void runPlanMatrix() throws IOException {
		int warmup = Math.max(0, Integer.getInteger(PLAN_MATRIX_WARMUP_PROPERTY, PLAN_MATRIX_DEFAULT_WARMUP));
		int measurements = Math.max(1,
				Integer.getInteger(PLAN_MATRIX_MEASUREMENTS_PROPERTY, PLAN_MATRIX_DEFAULT_MEASUREMENTS));
		List<Long> seeds = parsePlanMatrixSeeds();
		Path outputDir = planMatrixOutputDir();
		Files.createDirectories(outputDir);
		Path recordsPath = outputDir.resolve("records.jsonl");
		Files.deleteIfExists(recordsPath);
		Path tracePath = outputDir.resolve("optimizer-trace.jsonl");
		Files.deleteIfExists(tracePath);

		Theme onlyTheme = selectedTheme();
		Set<Integer> onlyIndexes = selectedIndexes();
		List<Theme> themes = new ArrayList<>();
		for (Theme theme : Theme.values()) {
			if (onlyTheme != null && onlyTheme != theme) {
				continue;
			}
			themes.add(theme);
		}

		String previousTracePath = System.getProperty(PLAN_TRACE_PATH_PROPERTY);
		System.setProperty(PLAN_TRACE_PATH_PROPERTY, tracePath.toString());
		try {
			for (PlanMatrixMode mode : PlanMatrixMode.values()) {
				for (PlanVariant variant : PlanVariant.values()) {
					List<PlanRunRecord> records = mode == PlanMatrixMode.COLD_ISOLATED
							? runPlanMatrixCold(themes, onlyIndexes, variant, mode, warmup, measurements)
							: runPlanMatrixWarm(themes, onlyIndexes, seeds, variant, mode, warmup, measurements);
					appendRecords(recordsPath, records);
				}
			}
		} finally {
			restoreProperty(PLAN_TRACE_PATH_PROPERTY, previousTracePath);
		}
		System.out.println("Plan matrix records written to " + recordsPath);
		System.out.println("Optimizer trace written to " + tracePath);
	}

	private Path runPlanRca(boolean singlePair) throws IOException {
		Theme onlyTheme = selectedTheme();
		Set<Integer> onlyIndexes = selectedIndexes();
		int iterations = Math.max(5, Integer.getInteger(PLAN_RCA_ITERATIONS_PROPERTY, PLAN_RCA_DEFAULT_ITERATIONS));
		Path outputDir = planRcaOutputDir();
		Files.createDirectories(outputDir);
		Path findingsPath = outputDir.resolve("findings.jsonl");
		Path summaryPath = outputDir.resolve("summary.md");
		List<RcaFindingRecord> findings = new ArrayList<>();
		for (Map.Entry<Theme, QueryPair> entry : RCA_QUERY_PAIRS.entrySet()) {
			Theme theme = entry.getKey();
			QueryPair pair = entry.getValue();
			if (onlyTheme != null && onlyTheme != theme) {
				continue;
			}
			List<Integer> indexes = new ArrayList<>();
			if (singlePair) {
				indexes.add(pair.regressionIndex);
			} else {
				indexes.add(pair.fasterIndex);
				indexes.add(pair.regressionIndex);
			}
			for (int queryIndex : indexes) {
				if (!onlyIndexes.isEmpty() && !onlyIndexes.contains(queryIndex)) {
					continue;
				}
				findings.add(collectRcaFinding(theme, queryIndex, true, iterations));
				findings.add(collectRcaFinding(theme, queryIndex, false, iterations));
			}
		}
		writeRcaFindings(findingsPath, findings);
		writeRcaSummary(summaryPath, findings);
		System.out.println("Plan RCA findings written to " + findingsPath);
		System.out.println("Plan RCA summary written to " + summaryPath);
		return outputDir;
	}

	private RcaFindingRecord collectRcaFinding(Theme theme, int queryIndex, boolean enableDp, int iterations)
			throws IOException {
		String mode = modeLabel(enableDp);
		File scenarioDir = new File(dataDir,
				"plan_rca_" + theme.name().toLowerCase() + "_" + queryIndex + "_" + mode.toLowerCase());
		long expected = ThemeQueryCatalog.expectedCountFor(theme, queryIndex);
		MemoryJoinStats learnedStats = new MemoryJoinStats(InvalidationSettings.disabled());
		RecordingJoinStatsProvider statsProvider = new RecordingJoinStatsProvider(learnedStats);
		LearnedJoinConfig config = new LearnedJoinConfig(LearnedJoinConfig.DEFAULT_DP_THRESHOLD, enableDp);
		LearningEvaluationStrategyFactory factory = new LearningEvaluationStrategyFactory(statsProvider, null, config);
		LmdbStore store = new LmdbStore(scenarioDir, ConfigUtil.createConfig());
		store.setEvaluationStrategyFactory(factory);

		List<List<String>> signatures = new ArrayList<>(iterations);
		long[] durations = new long[iterations];
		PlanSelectionSnapshot lastSnapshot = null;

		SailRepository repository = new SailRepository(store);
		repository.init();
		try {
			loadData(repository, theme);
			String query = ThemeQueryCatalog.queryFor(theme, queryIndex);
			try (SailRepositoryConnection connection = repository.getConnection()) {
				for (int i = 0; i < iterations; i++) {
					LearnedQueryJoinOptimizer.clearLastPlanSelectionSnapshot();
					TupleQuery tupleQuery = connection.prepareTupleQuery(query);
					long start = System.nanoTime();
					long count = executeCount(tupleQuery);
					durations[i] = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start);
					if (count != expected) {
						throw new IllegalStateException("Unexpected count for " + theme + "#" + queryIndex
								+ " " + mode + ": expected " + expected + " but got " + count);
					}
					TupleQuery explainQuery = connection.prepareTupleQuery(query);
					explainQuery.setMaxExecutionTime(EXPLAIN_TIMEOUT_SECONDS);
					Explanation explanation = explainQuery.explain(Explanation.Level.Timed);
					signatures.add(joinOrderSignature(explanation));
					lastSnapshot = LearnedQueryJoinOptimizer.getLastPlanSelectionSnapshot();
				}
			}
		} finally {
			repository.shutDown();
		}

		List<String> firstSignature = signatures.isEmpty() ? List.of() : signatures.get(0);
		List<String> stableSignature = stableSignature(signatures, AVERAGE_WINDOW);
		int driftCount = signatureDriftCount(signatures);
		long avgLast = averageLast(durations, AVERAGE_WINDOW);
		List<KeyDriverRow> topDrivers = toKeyDriverRows(statsProvider.topWorkDrivers(PLAN_RCA_TOP_KEYS, learnedStats));
		List<RcaStepRow> stepRows = buildStepRows(lastSnapshot, statsProvider);
		return new RcaFindingRecord(theme.name(), queryIndex, mode, signatureText(firstSignature),
				signatureText(stableSignature), driftCount, avgLast, snapshotReason(lastSnapshot),
				snapshotPlannerUsed(lastSnapshot),
				snapshotLabels(lastSnapshot == null ? null : lastSnapshot.getRawOrderLabels()),
				snapshotLabels(lastSnapshot == null ? null : lastSnapshot.getFinalOrderLabels()),
				snapshotRepair(lastSnapshot),
				snapshotLabels(lastSnapshot == null ? null : lastSnapshot.getRepairBeforeLabels()),
				snapshotLabels(lastSnapshot == null ? null : lastSnapshot.getRepairAfterLabels()),
				snapshotLabels(lastSnapshot == null ? null : lastSnapshot.getInitiallyBoundVars()),
				snapshotLabels(lastSnapshot == null ? null : lastSnapshot.getUnsupportedTargets()),
				rebalanceDiffNames(lastSnapshot), topDrivers, stepRows);
	}

	private String snapshotReason(PlanSelectionSnapshot snapshot) {
		return snapshot == null ? "" : snapshot.getReason();
	}

	private String snapshotPlannerUsed(PlanSelectionSnapshot snapshot) {
		return snapshot == null ? "none" : snapshot.getPlannerUsed();
	}

	private boolean snapshotRepair(PlanSelectionSnapshot snapshot) {
		return snapshot != null && snapshot.isRepairApplied();
	}

	private List<String> rebalanceDiffNames(PlanSelectionSnapshot snapshot) {
		if (snapshot == null || snapshot.getRebalanceDiffs().isEmpty()) {
			return List.of();
		}
		List<String> names = new ArrayList<>(snapshot.getRebalanceDiffs().size());
		for (PlanRewriteDiff diff : snapshot.getRebalanceDiffs()) {
			names.add(diff.getName());
		}
		return names;
	}

	private List<String> snapshotLabels(List<String> labels) {
		if (labels == null || labels.isEmpty()) {
			return List.of();
		}
		return List.copyOf(labels);
	}

	private List<KeyDriverRow> toKeyDriverRows(List<RecordingJoinStatsProvider.KeyDriver> drivers) {
		if (drivers.isEmpty()) {
			return List.of();
		}
		List<KeyDriverRow> rows = new ArrayList<>(drivers.size());
		for (RecordingJoinStatsProvider.KeyDriver driver : drivers) {
			rows.add(new KeyDriverRow(driver.key().toString(), driver.calls(), driver.avgResults(),
					driver.learnedAvg()));
		}
		return rows;
	}

	private List<RcaStepRow> buildStepRows(PlanSelectionSnapshot snapshot, RecordingJoinStatsProvider statsProvider) {
		if (snapshot == null) {
			return List.of();
		}
		int selected = snapshot.getSelectedCandidateIndex();
		if (selected < 0 || selected >= snapshot.getCandidates().size()) {
			return List.of();
		}
		org.eclipse.rdf4j.query.algebra.evaluation.optimizer.learned.JoinPlanCandidate candidate = snapshot
				.getCandidates()
				.get(selected);
		List<org.eclipse.rdf4j.query.algebra.evaluation.optimizer.learned.CardinalityEstimateBreakdown> breakdown = candidate
				.getEstimateBreakdown();
		List<TupleExpr> order = candidate.getOrder();
		if (order.isEmpty() || breakdown.isEmpty()) {
			return List.of();
		}
		List<RcaStepRow> rows = new ArrayList<>(Math.min(order.size(), breakdown.size()));
		Set<String> boundVars = new HashSet<>(snapshot.getInitiallyBoundVars());
		int steps = Math.min(order.size(), breakdown.size());
		for (int step = 0; step < steps; step++) {
			TupleExpr operand = order.get(step);
			String operandLabel = operandLabel(operand);
			PatternKey key = operandKey(operand, boundVars);
			long calls = key == null ? 0L : statsProvider.callsFor(key);
			double actualFanout = key == null ? 0.0d : statsProvider.averageResultsFor(key);
			var estimate = breakdown.get(step);
			rows.add(new RcaStepRow(step, operandLabel, estimate.getEstimatedRows(), estimate.getCumulativeCost(),
					key == null ? "" : key.toString(), calls, actualFanout));
			boundVars.addAll(filteredBindingNames(operand));
		}
		return rows;
	}

	private PatternKey operandKey(TupleExpr expr, Set<String> boundVars) {
		List<StatementPattern> patterns = StatementPatternCollector.process(expr);
		if (patterns.isEmpty()) {
			return null;
		}
		StatementPattern pattern = patterns.get(0);
		int mask = 0;
		if (isBound(pattern.getSubjectVar(), boundVars)) {
			mask |= PatternKey.SUBJECT_BOUND;
		}
		if (isBound(pattern.getPredicateVar(), boundVars)) {
			mask |= PatternKey.PREDICATE_BOUND;
		}
		if (isBound(pattern.getObjectVar(), boundVars)) {
			mask |= PatternKey.OBJECT_BOUND;
		}
		IRI predicateKey = null;
		if (pattern.getPredicateVar() != null && pattern.getPredicateVar().hasValue()
				&& pattern.getPredicateVar().getValue() instanceof IRI) {
			predicateKey = (IRI) pattern.getPredicateVar().getValue();
		}
		Value objectValue = pattern.getObjectVar() != null && pattern.getObjectVar().hasValue()
				? pattern.getObjectVar().getValue()
				: null;
		IRI statsPredicate = PatternKeys.predicateKey(predicateKey, objectValue);
		return new PatternKey(statsPredicate, mask);
	}

	private boolean isBound(Var var, Set<String> boundVars) {
		if (var == null) {
			return false;
		}
		if (var.hasValue()) {
			return true;
		}
		String name = var.getName();
		return name != null && boundVars.contains(name);
	}

	private Set<String> filteredBindingNames(TupleExpr expr) {
		Set<String> names = new HashSet<>(expr.getBindingNames());
		names.removeIf(name -> name.startsWith("_const_"));
		return names;
	}

	private String operandLabel(TupleExpr expr) {
		List<StatementPattern> patterns = StatementPatternCollector.process(expr);
		if (patterns.isEmpty()) {
			return expr.getClass().getSimpleName();
		}
		return predicateLabel(patterns.get(0).getPredicateVar());
	}

	private List<String> stableSignature(List<List<String>> signatures, int window) {
		if (signatures.isEmpty()) {
			return List.of();
		}
		int start = Math.max(0, signatures.size() - Math.max(1, window));
		Map<String, Integer> counts = new LinkedHashMap<>();
		String winner = signatureText(signatures.get(start));
		int winnerCount = 0;
		for (int i = start; i < signatures.size(); i++) {
			String signature = signatureText(signatures.get(i));
			int count = counts.merge(signature, 1, Integer::sum);
			if (count > winnerCount || (count == winnerCount && i == signatures.size() - 1)) {
				winner = signature;
				winnerCount = count;
			}
		}
		return parseSignatureText(winner);
	}

	private int signatureDriftCount(List<List<String>> signatures) {
		int drifts = 0;
		List<String> previous = null;
		for (List<String> signature : signatures) {
			if (previous != null && !previous.equals(signature)) {
				drifts++;
			}
			previous = signature;
		}
		return drifts;
	}

	private String signatureText(List<String> signature) {
		if (signature == null || signature.isEmpty()) {
			return "";
		}
		return String.join(" -> ", signature);
	}

	private List<String> parseSignatureText(String text) {
		if (text == null || text.isBlank()) {
			return List.of();
		}
		List<String> parts = new ArrayList<>();
		for (String token : text.split(" -> ")) {
			String trimmed = token.trim();
			if (!trimmed.isEmpty()) {
				parts.add(trimmed);
			}
		}
		return parts;
	}

	private void writeRcaFindings(Path output, List<RcaFindingRecord> findings) throws IOException {
		List<String> lines = new ArrayList<>(findings.size());
		for (RcaFindingRecord finding : findings) {
			lines.add(finding.toJson());
		}
		Files.write(output, lines, StandardCharsets.UTF_8, java.nio.file.StandardOpenOption.CREATE,
				java.nio.file.StandardOpenOption.TRUNCATE_EXISTING);
	}

	private void writeRcaSummary(Path output, List<RcaFindingRecord> findings) throws IOException {
		Map<String, RcaFindingRecord> byQueryMode = new LinkedHashMap<>();
		for (RcaFindingRecord finding : findings) {
			byQueryMode.put(finding.theme + "#" + finding.queryIndex + ":" + finding.mode, finding);
		}
		List<String> lines = new ArrayList<>();
		lines.add("# Plan RCA Summary");
		lines.add("");
		for (Map.Entry<Theme, QueryPair> entry : RCA_QUERY_PAIRS.entrySet()) {
			Theme theme = entry.getKey();
			QueryPair pair = entry.getValue();
			RcaFindingRecord dp = byQueryMode.get(theme.name() + "#" + pair.regressionIndex + ":DP");
			RcaFindingRecord greedy = byQueryMode.get(theme.name() + "#" + pair.regressionIndex + ":Greedy");
			if (dp == null || greedy == null) {
				continue;
			}
			double slowdownPct = greedy.avgLastMs <= 0 ? 0.0d
					: ((dp.avgLastMs - greedy.avgLastMs) / (double) greedy.avgLastMs) * 100.0d;
			String bucket = classifyBucket(dp, greedy);
			lines.add("## " + theme.name() + " #" + pair.regressionIndex);
			lines.add("");
			lines.add("- observed: DP avgLast20ms=" + dp.avgLastMs + ", Greedy avgLast20ms=" + greedy.avgLastMs
					+ ", slowdown=" + String.format("%.2f", slowdownPct) + "%");
			lines.add("- plan delta: DP stable=`" + dp.stableSignature + "`, Greedy stable=`" + greedy.stableSignature
					+ "`");
			lines.add("- top key deltas: DP top=`" + dp.topKeySummary() + "`, Greedy top=`" + greedy.topKeySummary()
					+ "`");
			lines.add("- likely bucket: " + bucket);
			lines.add("- strongest causal toggle evidence: not-run");
			lines.add("");
		}
		Files.writeString(output, String.join(System.lineSeparator(), lines) + System.lineSeparator(),
				StandardCharsets.UTF_8);
	}

	private String classifyBucket(RcaFindingRecord dp, RcaFindingRecord greedy) {
		if (dp.stableSignature.equals(greedy.stableSignature)) {
			return "6 (DP overhead/instability dominates)";
		}
		if (dp.repairApplied) {
			return "5 (disconnected repair interaction)";
		}
		if (!dp.rebalanceDiffNames.isEmpty()) {
			return "4 (rebalance override)";
		}
		if (dp.hasPredictedFanoutMiss()) {
			return "1 (intermediate explosion from estimate miss)";
		}
		return "2 (bound-mask/runtime cost mismatch)";
	}

